module top_module(
    input [3:0] a,
    input [3:0] b,
    input [1:0] opcode,
    output [3:0] result
);reg [3:0] obf_temp;

always @(*) begin
    case(opcode)
        2'b00: obf_temp = a + b;
        2'b01: obf_temp = a - b;
        2'b10: obf_temp = a & b;
        2'b11: obf_temp = a | b;
    endcase
end

assign result = obf_temp;

endmodule
